patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index a09f881e06595..27ff708521385 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -2309,8 +2309,16 @@ Instruction *InstCombinerImpl::foldBinopWithPhiOperands(BinaryOperator &BO) {
 Instruction *InstCombinerImpl::foldBinOpIntoSelectOrPhi(BinaryOperator &I) {
   auto TryFoldOperand = [&](unsigned OpIdx,
                             bool IsOtherParamConst) -> Instruction * {
-    if (auto *Sel = dyn_cast<SelectInst>(I.getOperand(OpIdx)))
-      return FoldOpIntoSelect(I, Sel, false, !IsOtherParamConst);
+    if (auto *Sel = dyn_cast<SelectInst>(I.getOperand(OpIdx))) {
+      // Fold binop(select(c, C, x), C2) => select(c, C3, binop(x, C2))
+      // when the select has multiple uses, as long as at least one
+      // arm and the binop operand are both constants.
+      bool MultiUse = IsOtherParamConst && !Sel->hasOneUser() &&
+                      (isa<Constant>(Sel->getTrueValue()) ||
+                       isa<Constant>(Sel->getFalseValue()));
+      return FoldOpIntoSelect(I, Sel, /*FoldWithMultiUse=*/MultiUse,
+                              !IsOtherParamConst);
+    }
     if (auto *PN = dyn_cast<PHINode>(I.getOperand(OpIdx)))
       return foldOpIntoPhi(I, PN);
     return nullptr;

